/* Community graph app. Reads window.GRAPH_DATA (generated by build.py). */
(() => {
  const DATA = window.GRAPH_DATA;
  if (!DATA) {
    document.getElementById("title").textContent =
      "data.js not found - run `python3 build.py` first";
    return;
  }

  // ---------- static setup ----------------------------------------------------
  document.getElementById("title").textContent = DATA.title;
  document.getElementById("subtitle").textContent = DATA.subtitle;
  document.title = DATA.title;

  const groups = DATA.groups;
  const groupIndex = new Map(groups.map((g, i) => [g.id, i]));
  const nodeGroup = (n) => n.group;
  const seriesVar = (gid) => `var(--series-${(groupIndex.get(gid) ?? 0) + 1})`;
  const groupLabel = (gid) => groups.find((g) => g.id === gid)?.label ?? gid;

  const papers = DATA.papers || [];

  const nodes = DATA.people.map((p) => ({ ...p }));
  const nodeById = new Map(nodes.map((n) => [n.id, n]));
  const links = (DATA.edges || []).map((e, i) => ({
    ...e,
    i,
    source: nodeById.get(e.source),
    target: nodeById.get(e.target),
  }));
  nodes.forEach((n) => (n.links = []));
  links.forEach((l) => { l.source.links.push(l); l.target.links.push(l); });

  // advising maps (directed)
  const advisorsOf = new Map(); // student id -> [{advisor, kind}]
  const studentsOf = new Map(); // advisor id -> [{student, kind}]
  (DATA.advising || []).forEach((r) => {
    if (!nodeById.has(r.advisor) || !nodeById.has(r.student)) return;
    if (!advisorsOf.has(r.student)) advisorsOf.set(r.student, []);
    advisorsOf.get(r.student).push(r);
    if (!studentsOf.has(r.advisor)) studentsOf.set(r.advisor, []);
    studentsOf.get(r.advisor).push(r);
  });

  // ---------- state -----------------------------------------------------------
  const weights = {};
  DATA.factors.forEach((f) => (weights[f.id] = f.default_weight));
  let threshold = 0.1;
  let advisingView = false;
  let topicSet = null; // Set of person ids matching the topic filter, or null
  const selectedTopics = new Set();
  const activeGroups = new Set(DATA.groups.map((g) => g.id));
  let selection = null; // {type: "node"|"edge", d}

  const topicLabels = new Map((DATA.topics || []).map((t) => [t.id, t.label]));
  const topicLabel = (t) => topicLabels.get(t) ?? t;

  // ---------- year range (filters which papers count) -------------------------
  // The slider starts at 2006; its leftmost position is an open "<2006"
  // bucket that includes all older papers.
  const paperYears = papers.map((p) => p.year).filter((y) => y);
  const dataMin = paperYears.length ? Math.min(...paperYears) : 2006;
  const YEAR_MIN = Math.max(2006, dataMin);
  const YEAR_MAX = paperYears.length ? Math.max(...paperYears) : 2026;
  let yearStart = YEAR_MIN, yearStop = YEAR_MAX;
  const fullRange = () => yearStart <= YEAR_MIN && yearStop >= YEAR_MAX;
  const paperInRange = (idx) => {
    const y = papers[idx].year;
    if (fullRange()) return true; // includes undated papers
    if (y == null) return false;
    const lower = yearStart <= YEAR_MIN ? -Infinity : yearStart;
    return y >= lower && y <= yearStop;
  };

  // ---------- scoring ---------------------------------------------------------
  function computeScores() {
    let maxScore = 0;
    for (const l of links) {
      l.papersInRange = (l.paper_ids || []).filter(paperInRange);
      let s = 0;
      for (const f of DATA.factors) {
        const raw = f.compute === "papers"
          ? l.papersInRange.length
          : (l.factors[f.id] || 0);
        // saturating factors grow monotonically with diminishing returns;
        // capped factors normalize against their max
        const norm = f.saturation
          ? raw / (raw + f.saturation)
          : Math.min(raw, f.max) / f.max;
        s += weights[f.id] * norm;
      }
      l.score = s;
      if (s > maxScore) maxScore = s;
    }
    for (const l of links) {
      l.rel = maxScore > 0 ? l.score / maxScore : 0;
      l.visible = l.rel > 0 && l.rel >= threshold;
      if (advisingView && !(l.advising || []).length) l.visible = false;
    }
    let maxDeg = 0;
    for (const n of nodes) {
      n.wdeg = n.links.reduce((a, l) => a + (l.visible ? l.score : 0), 0);
      if (n.wdeg > maxDeg) maxDeg = n.wdeg;
    }
    for (const n of nodes) {
      n.r = 5 + (maxDeg > 0 ? 9 * Math.sqrt(n.wdeg / maxDeg) : 0);
    }
  }

  // ---------- svg / simulation ------------------------------------------------
  const wrap = document.getElementById("graph-wrap");
  const svg = d3.select("#graph");

  // arrowhead for the advising view (fill follows the line's stroke)
  svg.append("defs").append("marker")
    .attr("id", "arrow")
    .attr("viewBox", "0 0 10 10")
    // anchored at the triangle BASE: the whole arrowhead sits beyond the
    // line's endpoint, hiding the round line cap behind it
    .attr("refX", 0).attr("refY", 5)
    .attr("markerUnits", "userSpaceOnUse")
    .attr("markerWidth", 11).attr("markerHeight", 11)
    .attr("orient", "auto-start-reverse")
    .append("path")
    .attr("d", "M 0 0 L 10 5 L 0 10 z")
    .attr("fill", "context-stroke");

  const zoomLayer = svg.append("g");
  const linkLayer = zoomLayer.append("g");
  const nodeLayer = zoomLayer.append("g");

  const zoom = d3.zoom().scaleExtent([0.15, 6])
    .on("zoom", (ev) => zoomLayer.attr("transform", ev.transform));
  svg.call(zoom).on("dblclick.zoom", null);
  svg.on("click", (ev) => { if (ev.target === svg.node()) select(null); });

  const size = () => [wrap.clientWidth, wrap.clientHeight];
  let [W, H] = size();

  const sim = d3.forceSimulation(nodes)
    .force("charge", d3.forceManyBody().strength(-280).distanceMax(650))
    .force("center", d3.forceCenter(W / 2, H / 2))
    .force("x", d3.forceX(W / 2).strength(0.025))
    .force("y", d3.forceY(H / 2).strength(0.025))
    .force("collide", d3.forceCollide().radius((d) => d.r + 9))
    .force("link", d3.forceLink().id((d) => d.id));

  new ResizeObserver(() => {
    [W, H] = size();
    sim.force("center", d3.forceCenter(W / 2, H / 2));
    sim.force("x", d3.forceX(W / 2).strength(0.04));
    sim.force("y", d3.forceY(H / 2).strength(0.04));
    sim.alpha(0.2).restart();
  }).observe(wrap);

  const linkSel = linkLayer.selectAll("g.linkg").data(links).join("g")
    .attr("class", "linkg");
  const linkLine = linkSel.append("line").attr("class", "link");
  const linkHit = linkSel.append("line").attr("class", "link-hit");

  const nodeSel = nodeLayer.selectAll("g.node").data(nodes).join("g")
    .attr("class", "node");
  const circles = nodeSel.append("circle"); // fill applied in refreshClasses
  const labels = nodeSel.append("text")
    .attr("dy", "0.32em")
    .text((d) => d.name);

  // In the advising view the line stops at the student node so the arrowhead
  // is visible; otherwise it runs center to center.
  function lineEnds(l) {
    let { x: x1, y: y1 } = l.source;
    let { x: x2, y: y2 } = l.target;
    if (advisingView && (l.advising || []).length) {
      const rec = l.advising[0];
      const student = nodeById.get(rec.student);
      const advisor = nodeById.get(rec.advisor);
      const dx = student.x - advisor.x, dy = student.y - advisor.y;
      const dist = Math.hypot(dx, dy) || 1;
      // line ends 11px (one arrow length) before the node edge; the marker
      // fills that gap so the tip lands just off the circle
      const trim = (student.r + 14) / dist;
      x1 = advisor.x; y1 = advisor.y;
      x2 = student.x - dx * trim;
      y2 = student.y - dy * trim;
    }
    return [x1, y1, x2, y2];
  }

  sim.on("tick", () => {
    linkLine.each(function (l) {
      const [x1, y1, x2, y2] = lineEnds(l);
      d3.select(this).attr("x1", x1).attr("y1", y1).attr("x2", x2).attr("y2", y2);
    });
    linkHit.attr("x1", (d) => d.source.x).attr("y1", (d) => d.source.y)
           .attr("x2", (d) => d.target.x).attr("y2", (d) => d.target.y);
    nodeSel.attr("transform", (d) => `translate(${d.x},${d.y})`);
  });

  nodeSel.call(d3.drag()
    .on("start", (ev, d) => {
      if (!ev.active) sim.alphaTarget(0.25).restart();
      d.fx = d.x; d.fy = d.y;
    })
    .on("drag", (ev, d) => { d.fx = ev.x; d.fy = ev.y; })
    .on("end", (ev, d) => {
      if (!ev.active) sim.alphaTarget(0);
      d.pinned = true;
      refreshClasses();
    }));
  nodeSel.on("dblclick", (ev, d) => {
    d.fx = d.fy = null; d.pinned = false;
    refreshClasses();
    sim.alpha(0.2).restart();
    ev.stopPropagation();
  });

  // ---------- hover ----------------------------------------------------------
  const tooltip = document.getElementById("tooltip");
  function showTip(ev, html) {
    tooltip.innerHTML = html;
    tooltip.hidden = false;
    const r = wrap.getBoundingClientRect();
    let x = ev.clientX - r.left + 14, y = ev.clientY - r.top + 10;
    const tw = tooltip.offsetWidth, th = tooltip.offsetHeight;
    if (x + tw > r.width - 8) x = ev.clientX - r.left - tw - 10;
    if (y + th > r.height - 8) y = ev.clientY - r.top - th - 10;
    tooltip.style.left = x + "px";
    tooltip.style.top = y + "px";
  }
  const hideTip = () => (tooltip.hidden = true);
  const esc = (s) => String(s ?? "").replace(/[&<>"]/g,
    (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));

  let hovered = null;
  nodeSel
    .on("mouseenter", (ev, d) => {
      hovered = d;
      const np = (d.papers || []).length;
      showTip(ev, `<div class="tt-title">${esc(d.name)}</div>
        <div class="tt-sub">${esc(d.affiliation)}</div>
        <div class="tt-sub">${esc(groupLabel(nodeGroup(d)))} · ${d.links.filter(l => l.visible).length} connections${np ? ` · ${np} papers` : ""}</div>`);
      refreshClasses();
    })
    .on("mousemove", (ev) => showTip(ev, tooltip.innerHTML))
    .on("mouseleave", () => { hovered = null; hideTip(); refreshClasses(); })
    .on("click", (ev, d) => { select({ type: "node", d }); ev.stopPropagation(); });

  linkHit
    .on("mouseenter", (ev, l) => {
      const np = (l.paper_ids || []).length;
      showTip(ev,
        `<div class="tt-title">${esc(l.source.name)} — ${esc(l.target.name)}</div>
         <div class="tt-sub">closeness ${(100 * l.rel).toFixed(0)}%${np ? ` · ${np} joint papers` : ""} · click for details</div>`);
    })
    .on("mousemove", (ev) => showTip(ev, tooltip.innerHTML))
    .on("mouseleave", hideTip)
    .on("click", (ev, l) => { select({ type: "edge", d: l }); ev.stopPropagation(); });

  // ---------- rendering state -> classes/attrs -------------------------------
  function nodeActive(n) {
    return activeGroups.has(nodeGroup(n)) && (!topicSet || topicSet.has(n.id));
  }

  function neighborSetOf(n, includeHidden = false) {
    const s = new Set([n.id]);
    n.links.forEach((l) => {
      if (l.visible || includeHidden) { s.add(l.source.id); s.add(l.target.id); }
    });
    return s;
  }

  function refreshClasses() {
    const selNode = selection?.type === "node" ? selection.d : null;
    const focus = hovered || selNode;
    // a selected person reveals all their edges, threshold or not
    const focusSet = focus ? neighborSetOf(focus, focus === selNode) : null;
    const selEdge = selection?.type === "edge" ? selection.d : null;
    const revealed = (l) => selNode && (l.source === selNode || l.target === selNode);

    nodeSel
      .classed("selected", (d) => selection?.type === "node" && selection.d === d)
      .classed("pinned", (d) => d.pinned)
      .classed("faded", (d) => {
        if (!nodeActive(d)) return true;
        if (focusSet && !focusSet.has(d.id)) return true;
        if (selEdge && d !== selEdge.source && d !== selEdge.target) return true;
        return false;
      });
    circles.attr("r", (d) => d.r).style("fill", (d) => seriesVar(nodeGroup(d)));
    labels.attr("x", (d) => d.r + 3);

    linkSel.style("display", (l) => (l.visible || revealed(l) ? null : "none"));
    linkLine
      .classed("selected", (l) => l === selEdge)
      .classed("subthreshold", (l) => !l.visible && revealed(l))
      .classed("advising", (l) => advisingView && (l.advising || []).length > 0)
      .attr("marker-end", (l) =>
        advisingView && (l.advising || []).length ? "url(#arrow)" : null)
      .classed("faded", (l) => {
        if (!nodeActive(l.source) || !nodeActive(l.target)) return true;
        if (focus && l.source !== focus && l.target !== focus) return true;
        if (selEdge && l !== selEdge) return true;
        return false;
      })
      .attr("stroke-width", (l) => 1 + 4 * l.rel)
      .attr("stroke-opacity", (l) => {
        // weak edges recede until a node/edge is focused
        const related = (focus && (l.source === focus || l.target === focus)) ||
                        l === selEdge;
        if (related) return l.visible ? 0.85 : 0.55;
        return 0.06 + 0.55 * Math.pow(l.rel, 1.6);
      });
  }

  function refreshForces(reheat = true) {
    const visible = links.filter((l) => l.visible);
    sim.force("link")
      .links(visible)
      .distance((l) => 60 + 190 * (1 - l.rel))
      .strength((l) => 0.06 + 0.4 * l.rel);
    sim.force("collide").radius((d) => d.r + 9);
    if (reheat) sim.alpha(0.5).restart();
  }

  function update(reheat = true) {
    computeScores();
    refreshForces(reheat);
    refreshClasses();
    renderStats();
    if (selection) renderDetails();
  }

  function renderStats() {
    const vis = links.filter((l) => l.visible).length;
    const nPapers = fullRange()
      ? papers.length
      : papers.filter((_, i) => paperInRange(i)).length;
    document.getElementById("stats").textContent =
      `${nodes.length} people · ${vis}/${links.length} edges · ` +
      `${nPapers}${fullRange() ? "" : `/${papers.length}`} papers · ` +
      `${(DATA.advising || []).length} advising ties · generated ${DATA.generated}`;
  }

  // ---------- controls --------------------------------------------------------
  // filled-progress styling for single sliders (CSS reads --fill)
  const paintFill = (el) => {
    const min = Number(el.min) || 0, max = Number(el.max) || 1;
    el.style.setProperty("--fill", `${(100 * (el.value - min)) / (max - min || 1)}%`);
  };

  const slidersDiv = document.getElementById("weight-sliders");
  DATA.factors.forEach((f) => {
    const row = document.createElement("div");
    row.className = "slider-row";
    row.innerHTML = `
      <div class="slider-label">
        <span class="fname" title="${esc(f.description)}">${esc(f.label)}${f.kind === "computed" ? " ·" : ""}</span>
        <span class="slider-value"></span>
      </div>`;
    const input = document.createElement("input");
    input.type = "range";
    input.min = 0; input.max = 1; input.step = 0.05;
    input.value = f.default_weight;
    const val = row.querySelector(".slider-value");
    const paint = () => {
      val.textContent = Number(input.value).toFixed(2);
      paintFill(input);
    };
    paint();
    input.addEventListener("input", () => {
      weights[f.id] = Number(input.value);
      paint();
      update();
    });
    row.appendChild(input);
    slidersDiv.appendChild(row);
    f._input = input;
  });

  document.getElementById("reset-weights").addEventListener("click", () => {
    DATA.factors.forEach((f) => {
      weights[f.id] = f.default_weight;
      f._input.value = f.default_weight;
      f._input.dispatchEvent(new Event("input"));
    });
  });

  const yearStartInput = document.getElementById("year-start");
  const yearStopInput = document.getElementById("year-stop");
  const yearsValue = document.getElementById("years-value");
  [yearStartInput, yearStopInput].forEach((el) => {
    el.min = YEAR_MIN; el.max = YEAR_MAX; el.step = 1;
  });
  yearStartInput.value = YEAR_MIN;
  yearStopInput.value = YEAR_MAX;
  const yearsFill = document.getElementById("years-fill");
  function paintYears() {
    const startLabel = yearStart <= YEAR_MIN ? `<${YEAR_MIN}` : yearStart;
    yearsValue.textContent = `${startLabel} – ${yearStop}`;
    const span = YEAR_MAX - YEAR_MIN || 1;
    yearsFill.style.left = `${(100 * (yearStart - YEAR_MIN)) / span}%`;
    yearsFill.style.width = `${(100 * (yearStop - yearStart)) / span}%`;
    // keep the reachable thumb on top when both sit at one end
    const mid = (YEAR_MIN + YEAR_MAX) / 2;
    yearStartInput.style.zIndex = yearStart > mid ? 3 : 2;
    yearStopInput.style.zIndex = yearStart > mid ? 2 : 3;
  }
  paintYears();
  function onYearInput() {
    let a = Number(yearStartInput.value), b = Number(yearStopInput.value);
    if (a > b) { // keep start <= stop by dragging the other thumb along
      if (this === yearStartInput) { b = a; yearStopInput.value = a; }
      else { a = b; yearStartInput.value = b; }
    }
    yearStart = a; yearStop = b;
    paintYears();
    update();
  }
  yearStartInput.addEventListener("input", onYearInput);
  yearStopInput.addEventListener("input", onYearInput);
  if (!papers.length) document.getElementById("years-row").hidden = true;

  const thInput = document.getElementById("threshold");
  paintFill(thInput);
  thInput.addEventListener("input", () => {
    threshold = Number(thInput.value);
    document.getElementById("threshold-value").textContent =
      `${Math.round(100 * threshold)}%`;
    paintFill(thInput);
    update(false);
    sim.alpha(0.3).restart();
  });

  document.getElementById("advising-toggle").addEventListener("change", (ev) => {
    advisingView = ev.target.checked;
    update();
  });

  // ---------- topic filter (whitelist chips; multiple selected = OR) ----------
  const topicInput = document.getElementById("topic-search");
  const topicChips = document.getElementById("topic-chips");
  const topicCount = document.getElementById("topic-count");
  const topicClear = document.getElementById("topic-clear");
  const topicPeople = new Map((DATA.topics || []).map((t) => [
    t.id, nodes.filter((n) => (n.topics || []).includes(t.id)).map((n) => n.id),
  ]));

  function applyTopics() {
    if (selectedTopics.size === 0) {
      topicSet = null;
      topicCount.textContent = "";
    } else {
      topicSet = new Set();
      selectedTopics.forEach((t) => (topicPeople.get(t) || []).forEach((p) => topicSet.add(p)));
      topicCount.textContent = `${topicSet.size} people match`;
    }
    topicClear.hidden = selectedTopics.size === 0;
    renderTopicChips();
    refreshClasses();
  }

  function renderTopicChips() {
    const q = topicInput.value.trim().toLowerCase();
    topicChips.innerHTML = "";
    (DATA.topics || [])
      .filter((t) => selectedTopics.has(t.id) ||
                     !q || t.label.toLowerCase().includes(q))
      .forEach((t) => {
        const count = (topicPeople.get(t.id) || []).length;
        if (!count && !selectedTopics.has(t.id)) return;
        const b = document.createElement("button");
        b.className = "topic-chip" + (selectedTopics.has(t.id) ? " on" : "");
        b.innerHTML = `${esc(t.label)} <span class="chip-count">${count}</span>`;
        b.addEventListener("click", () => {
          selectedTopics.has(t.id) ? selectedTopics.delete(t.id) : selectedTopics.add(t.id);
          applyTopics();
        });
        topicChips.appendChild(b);
      });
  }

  topicInput.addEventListener("input", renderTopicChips);
  topicClear.addEventListener("click", () => {
    selectedTopics.clear();
    topicInput.value = "";
    applyTopics();
  });
  renderTopicChips();

  // ---------- legend ----------------------------------------------------------
  const legendDiv = document.getElementById("legend");
  function renderLegend() {
    legendDiv.innerHTML = "";
    groups.forEach((g) => {
      const count = nodes.filter((n) => nodeGroup(n) === g.id).length;
      const b = document.createElement("button");
      b.className = "legend-row" + (activeGroups.has(g.id) ? "" : " dimmed");
      b.innerHTML = `<span class="swatch" style="background:${seriesVar(g.id)}"></span>
        <span>${esc(g.label)}</span><span class="legend-count">${count}</span>`;
      b.addEventListener("click", () => {
        if (activeGroups.has(g.id)) activeGroups.delete(g.id);
        else activeGroups.add(g.id);
        renderLegend();
        refreshClasses();
      });
      legendDiv.appendChild(b);
    });
  }
  renderLegend();

  // ---------- search + people list -------------------------------------------
  const searchInput = document.getElementById("search");
  const resultsDiv = document.getElementById("search-results");
  searchInput.addEventListener("input", () => {
    const q = searchInput.value.trim().toLowerCase();
    resultsDiv.innerHTML = "";
    if (q.length < 2) return;
    nodes
      .filter((n) => n.name.toLowerCase().includes(q) ||
                     (n.affiliation || "").toLowerCase().includes(q))
      .slice(0, 8)
      .forEach((n) => {
        const b = document.createElement("button");
        b.className = "search-hit";
        b.innerHTML = `${esc(n.name)} <span class="aff">· ${esc(n.affiliation)}</span>`;
        b.addEventListener("click", () => {
          focusNode(n);
          resultsDiv.innerHTML = "";
          searchInput.value = "";
        });
        resultsDiv.appendChild(b);
      });
  });

  const peopleDiv = document.getElementById("people-list");
  function renderPeopleList() {
    peopleDiv.innerHTML = "";
    [...nodes].sort((a, b) => a.name.localeCompare(b.name)).forEach((n) => {
      const b = document.createElement("button");
      b.className = "person-row";
      b.innerHTML = `<span class="swatch" style="background:${seriesVar(nodeGroup(n))}"></span>
        <span>${esc(n.name)}</span><span class="aff">${esc(n.affiliation)}</span>`;
      b.addEventListener("click", () => focusNode(n));
      peopleDiv.appendChild(b);
    });
  }
  renderPeopleList();

  function focusNode(n) {
    sidebarEl.classList.remove("open"); // mobile sheet closes on selection
    select({ type: "node", d: n });
    const t = d3.zoomTransform(svg.node());
    const k = Math.max(t.k, 1);
    svg.transition().duration(500).call(
      zoom.transform,
      d3.zoomIdentity.translate(W / 2 - k * n.x, H / 2 - k * n.y).scale(k)
    );
  }

  // ---------- details panel ---------------------------------------------------
  const detailsEl = document.getElementById("details");
  const detailsBody = document.getElementById("details-body");
  document.getElementById("details-close").addEventListener("click", () => select(null));

  function select(sel) {
    selection = sel;
    detailsEl.hidden = !sel;
    if (sel) renderDetails();
    refreshClasses();
  }

  const webSearchLink = (n) =>
    `https://www.google.com/search?q=${encodeURIComponent(n.name + " " + (n.affiliation || ""))}`;

  const personLink = (n) => `<a href="#" data-person="${esc(n.id)}">${esc(n.name)}</a>`;
  const kindLabel = (k) => (k === "phd" ? "PhD" : k);

  function renderDetails() {
    if (!selection) return;
    detailsBody.innerHTML =
      selection.type === "node" ? personHtml(selection.d) : edgeHtml(selection.d);
    detailsBody.querySelectorAll("[data-person]").forEach((a) =>
      a.addEventListener("click", (ev) => {
        ev.preventDefault();
        focusNode(nodeById.get(a.dataset.person));
      }));
    detailsBody.querySelectorAll("[data-edge]").forEach((a) =>
      a.addEventListener("click", (ev) => {
        ev.preventDefault();
        select({ type: "edge", d: links[Number(a.dataset.edge)] });
      }));
  }

  function paperLi(idx, opts = {}) {
    const p = papers[idx];
    const title = p.url
      ? `<a href="${esc(p.url)}" target="_blank" rel="noopener">${esc(p.title)}</a>`
      : esc(p.title);
    const withAuthors = opts.omit
      ? p.authors.filter((a) => !opts.omit.has(a))
      : p.authors;
    const names = withAuthors.map((a) => personLink(nodeById.get(a))).join(", ");
    return `<li>${title}
      <span class="aff">(${p.year ?? "?"}${p.venue ? `, ${esc(p.venue)}` : ""})</span>
      ${names ? `<div class="paper-authors">with ${names}</div>` : ""}</li>`;
  }

  function personHtml(n) {
    const advisors = (advisorsOf.get(n.id) || []).map((r) =>
      `<li>${personLink(nodeById.get(r.advisor))} <span class="chip">${kindLabel(r.kind)}</span></li>`).join("");
    const students = (studentsOf.get(n.id) || []).map((r) =>
      `<li>${personLink(nodeById.get(r.student))} <span class="chip">${kindLabel(r.kind)}</span></li>`).join("");

    const myPapers = (n.papers || []).filter(paperInRange)
      .sort((a, b) => (papers[b].year ?? 0) - (papers[a].year ?? 0));
    const omit = new Set([n.id]);
    const paperItems = myPapers.map((idx) => paperLi(idx, { omit })).join("");

    const conns = [...n.links]
      .sort((a, b) => b.score - a.score)
      .map((l) => {
        const other = l.source === n ? l.target : l.source;
        return `<button class="conn-row" data-edge="${l.i}">
          <span class="swatch" style="background:${seriesVar(nodeGroup(other))}"></span>
          <span>${esc(other.name)}</span>
          <span class="conn-bar-wrap"><span class="conn-bar" style="width:${Math.round(100 * l.rel)}%"></span></span>
        </button>`;
      }).join("");

    return `
      ${n.photo ? `<img class="photo" src="${esc(n.photo)}" alt="" loading="lazy"
        referrerpolicy="no-referrer" onerror="this.remove()">` : ""}
      <h2>${esc(n.name)}</h2>
      <div class="aff">${esc(n.affiliation)}</div>
      <div style="margin-top:6px">
        <span class="chip" style="border-color:transparent;background:color-mix(in srgb, ${seriesVar(nodeGroup(n))} 18%, transparent)">${esc(groupLabel(nodeGroup(n)))}</span>
        ${(n.topics || []).map((t) => `<span class="chip">${esc(topicLabel(t))}</span>`).join("")}
      </div>
      ${n.notes ? `<p class="notes">${esc(n.notes)}</p>` : ""}
      <h3>Links</h3>
      <div>${n.website ? `<a href="${esc(n.website)}" target="_blank" rel="noopener">Website</a> · ` : ""}
        <a href="${webSearchLink(n)}" target="_blank" rel="noopener">Search the web</a></div>
      ${advisors ? `<h3>Advisors</h3><ul class="plain">${advisors}</ul>` : ""}
      ${students ? `<h3>Students & postdocs</h3><ul class="plain">${students}</ul>` : ""}
      <h3>Connections (${n.links.length})</h3>
      ${conns || `<div class="aff">None.</div>`}
      ${paperItems ? `<h3>Tracked papers (${myPapers.length})</h3><ul class="papers">${paperItems}</ul>` : ""}`;
  }

  function edgeHtml(l) {
    const rows = DATA.factors.map((f) => {
      const raw = f.compute === "papers"
        ? (l.papersInRange || []).length
        : (l.factors[f.id] || 0);
      const norm = f.saturation
        ? raw / (raw + f.saturation)
        : Math.min(raw, f.max) / f.max;
      const contrib = weights[f.id] * norm;
      const valCell = f.saturation ? `${raw}` : `${raw}&thinsp;/&thinsp;${f.max}`;
      return `<tr class="${raw === 0 ? "zero" : ""}" title="${esc(f.description)}">
        <td>${esc(f.label)}</td>
        <td class="num">${valCell}</td>
        <td class="num">×&thinsp;${weights[f.id].toFixed(2)}</td>
        <td class="num">${contrib.toFixed(2)}</td>
      </tr>`;
    }).join("");

    const adv = (l.advising || []).map((r) =>
      `<div>${personLink(nodeById.get(r.advisor))} → ${personLink(nodeById.get(r.student))}
       <span class="chip">${kindLabel(r.kind)}</span></div>`).join("");
    const jointPapers = [...(l.papersInRange || l.paper_ids || [])]
      .sort((a, b) => (papers[b].year ?? 0) - (papers[a].year ?? 0));
    const omit = new Set([l.source.id, l.target.id]);
    const paperItems = jointPapers.map((idx) => paperLi(idx, { omit })).join("");

    return `
      <h2 style="font-size:15px">${personLink(l.source)} &nbsp;·&nbsp; ${personLink(l.target)}</h2>
      <div class="aff">Relationship — closeness ${(100 * l.rel).toFixed(0)}% of strongest edge</div>
      ${l.notes ? `<p class="notes">${esc(l.notes)}</p>` : ""}
      ${adv ? `<h3>Advising</h3>${adv}` : ""}
      <h3>Factor breakdown</h3>
      <table class="factor-table">
        <thead><tr><th>Factor</th><th>Value</th><th>Weight</th><th>Score</th></tr></thead>
        <tbody>${rows}</tbody>
        <tfoot><tr><td>Total</td><td></td><td></td><td class="num">${l.score.toFixed(2)}</td></tr></tfoot>
      </table>
      ${paperItems ? `<h3>Joint papers (${jointPapers.length})</h3><ul class="papers">${paperItems}</ul>` : ""}
      ${(l.links || []).length ? `<h3>References</h3><ul style="margin:4px 0;padding-left:18px">
        ${l.links.map((u) => `<li><a href="${esc(u)}" target="_blank" rel="noopener">${esc(u)}</a></li>`).join("")}</ul>` : ""}`;
  }

  // ---------- mobile sidebar sheet --------------------------------------------
  const sidebarEl = document.getElementById("sidebar");
  document.getElementById("sidebar-open").addEventListener("click", () =>
    sidebarEl.classList.add("open"));
  document.getElementById("sidebar-close").addEventListener("click", () =>
    sidebarEl.classList.remove("open"));

  // ---------- theme toggle ----------------------------------------------------
  const themeBtn = document.getElementById("theme-toggle");
  const THEMES = ["auto", "light", "dark"];
  function applyTheme(t) {
    if (t === "auto") delete document.documentElement.dataset.theme;
    else document.documentElement.dataset.theme = t;
    themeBtn.textContent = `theme: ${t}`;
  }
  let theme = localStorage.getItem("nla-theme") || "auto";
  applyTheme(theme);
  themeBtn.addEventListener("click", () => {
    theme = THEMES[(THEMES.indexOf(theme) + 1) % THEMES.length];
    localStorage.setItem("nla-theme", theme);
    applyTheme(theme);
  });

  // ---------- go --------------------------------------------------------------
  document.getElementById("threshold-value").textContent =
    `${Math.round(100 * threshold)}%`;

  // Settle the initial layout using EVERY scored edge (so hidden relationships
  // still shape the geography), synchronously and off-screen; then hand the
  // simulation over to the visible edge set for interaction.
  computeScores();
  sim.stop();
  sim.force("link")
    .links(links.filter((l) => l.score > 0))
    .distance((l) => 60 + 190 * (1 - l.rel))
    .strength((l) => 0.06 + 0.4 * l.rel);
  sim.alpha(1);
  for (let i = 0; i < 300; i++) sim.tick();
  update(false);           // swaps the link force to visible edges only
  sim.alpha(0.12).restart(); // brief gentle settle under the new force set
})();
